// 1. Grab your raw clumped text
const rawText = $input.first().json.output || "";

// 2. Extract the Timestamp
// (Added 'i' flag at the end so it works even if it says "timestamp:")
const timestampMatch = rawText.match(/Timestamp:\s*([^\n]+)/i);
const timestamp = timestampMatch ? timestampMatch[1].trim() : "";

// 3. Extract the User Question
// (Added 'i' flag for case-insensitivity)
const questionMatch = rawText.match(/User question:\s*([^\n]+)/i);
const userQuestion = questionMatch ? questionMatch[1].trim() : "";

// 4. Extract the SQL Query
// FIX: Looks for "executed:" OR "used:" and grabs everything up to the semicolon.
// This prevents it from failing if the AI changes line breaks (\n\n).
const sqlMatch = rawText.match(/SQL query (?:executed|used):\s*([\s\S]*?;)/i);
const sqlQuery = sqlMatch ? sqlMatch[1].trim() : "";

// 5. Extract the Results / AI Output
// FIX: Instead of looking for exact words like "SQL results" or "top", 
// we safely grab absolutely everything that comes after the SQL semicolon.
let results = "";
const lastSemicolonIndex = rawText.lastIndexOf(";");
if (lastSemicolonIndex !== -1) {
    results = rawText.substring(lastSemicolonIndex + 1).trim();
}

// 6. Return the beautifully separated columns!
return {
  json: {
    Timestamp: timestamp,
    User_Question: userQuestion,
    SQL_Query: sqlQuery,
    AI_Response: results
  }
};
